import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface StockMetadata {
  symbol: string;
  name: string;
  sector?: string;
  price?: number;
  changePercent?: number;
}

export interface AnalysisSection {
  score: number; // 0-100
  summary: string;
  details: string[];
}

export interface TradeSetup {
  action: 'BUY' | 'SELL' | 'HOLD';
  entryPriceLow: number;
  entryPriceHigh: number;
  targetPrice: number;
  stopLoss: number;
  probability: number; // 0-100%
  timeframe: string; // e.g., "2-4 Weeks"
}

export interface AIAnalysisResult {
  symbol: string;
  name: string;
  timestamp: string;
  overallScore: number; // 0-100
  trend: 'BULLISH' | 'BEARISH' | 'NEUTRAL';

  fundamental: AnalysisSection;
  technical: AnalysisSection;
  chips: AnalysisSection; // Institutional holdings/flow

  tradeSetup: TradeSetup;
  riskAnalysis: string;
}

export enum AnalysisStatus {
  IDLE,
  LOADING,
  SUCCESS,
  ERROR
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIAnalysisResult } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Schema for structured output
const analysisSchema = {
  type: Type.OBJECT,
  properties: {
    symbol: { type: Type.STRING },
    name: { type: Type.STRING },
    overallScore: { type: Type.NUMBER, description: "Overall score 0-100" },
    trend: { type: Type.STRING, enum: ["BULLISH", "BEARISH", "NEUTRAL"] },
    fundamental: {
      type: Type.OBJECT,
      properties: {
        score: { type: Type.NUMBER },
        summary: { type: Type.STRING },
        details: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    },
    technical: {
      type: Type.OBJECT,
      properties: {
        score: { type: Type.NUMBER },
        summary: { type: Type.STRING },
        details: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    },
    chips: {
      type: Type.OBJECT,
      properties: {
        score: { type: Type.NUMBER },
        summary: { type: Type.STRING, description: "Institutional investor analysis" },
        details: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    },
    tradeSetup: {
      type: Type.OBJECT,
      properties: {
        action: { type: Type.STRING, enum: ["BUY", "SELL", "HOLD"] },
        entryPriceLow: { type: Type.NUMBER },
        entryPriceHigh: { type: Type.NUMBER },
        targetPrice: { type: Type.NUMBER },
        stopLoss: { type: Type.NUMBER },
        probability: { type: Type.NUMBER, description: "Success probability percentage 0-100" },
        timeframe: { type: Type.STRING }
      }
    },
    riskAnalysis: { type: Type.STRING }
  },
  required: ["symbol", "name", "overallScore", "trend", "fundamental", "technical", "chips", "tradeSetup", "riskAnalysis"]
};

export const analyzeStock = async (query: string): Promise<AIAnalysisResult> => {
  try {
    const prompt = `
      Act as a world-class financial analyst and AI trading algorithm.
      Analyze the stock identified by "${query}" (If it is a Taiwanese stock, treat it as such. If US, treat as US).

      Perform a comprehensive analysis based on:
      1. Fundamentals (Earnings, P/E, Revenue Growth, Industry position)
      2. Technicals (Moving Averages, RSI, MACD, Volume, Patterns)
      3. Chips/Flow (Institutional buying/selling, Insider moves - simulate realistic data based on typical behavior for this stock type if real-time is unavailable)

      Predict the market direction, calculate a success probability, and determine precise buy/sell points.
      Current date is ${new Date().toLocaleDateString()}.

      Ensure the prices are in the correct currency for the stock (TWD for TW stocks, USD for US stocks).
    `;

    // Using gemini-3-pro-preview for deep reasoning capability
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        thinkingConfig: { thinkingBudget: 2048 } // Allow some thinking for math/logic
      }
    });

    if (!response.text) {
      throw new Error("No response from AI");
    }

    const data = JSON.parse(response.text) as AIAnalysisResult;
    // Add timestamp manually
    data.timestamp = new Date().toLocaleString();

    return data;
  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

export const getMarketOverview = async (): Promise<any[]> => {
    // A lighter prompt for the dashboard lists
    const prompt = `
        Generate a JSON list of 5 currently trending stocks (mix of TW and US Tech) that are popular among traders today.
        Return an array of objects with: symbol, name, price (approx), changePercent (approx).
    `;
     const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      }
    });

    try {
        return JSON.parse(response.text || "[]");
    } catch (e) {
        return [];
    }
}

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Label } from 'recharts';

interface RadialChartProps {
  score: number;
  label: string;
  color: string;
}

const RadialChart: React.FC<RadialChartProps> = ({ score, label, color }) => {
  const data = [
    { name: 'Score', value: score },
    { name: 'Remainder', value: 100 - score },
  ];

  return (
    <div className="flex flex-col items-center justify-center h-full">
      <div className="h-24 w-24 relative">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie
              data={data}
              cx="50%"
              cy="50%"
              innerRadius={35}
              outerRadius={45}
              startAngle={90}
              endAngle={-270}
              dataKey="value"
              stroke="none"
            >
              <Cell key={`cell-0`} fill={color} />
              <Cell key={`cell-1`} fill="#334155" /> 
            </Pie>

          </PieChart>
        </ResponsiveContainer>
        <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-xl font-bold text-white">{score}</span>
        </div>
      </div>
      <span className="text-xs text-gray-400 mt-1 uppercase tracking-wider">{label}</span>
    </div>
  );
};

export default RadialChart;

