        entryPriceHigh: { type: Type.NUMBER },
        targetPrice: { type: Type.NUMBER },
        stopLoss: { type: Type.NUMBER },
        probability: { type: Type.NUMBER, description: "Success probability percentage 0-100" },
        timeframe: { type: Type.STRING }
      },
      required: ["action", "entryPriceLow", "entryPriceHigh", "targetPrice", "stopLoss", "probability", "timeframe"]
    },
    riskAnalysis: { type: Type.STRING }
  },
  required: ["symbol", "name", "overallScore", "trend", "fundamental", "technical", "chips", "tradeSetup", "riskAnalysis"]
};

export const analyzeStock = async (query: string): Promise<AIAnalysisResult> => {
  try {
    const prompt = `
      Act as a world-class financial analyst and AI trading algorithm.
      Analyze the stock identified by "${query}" (If it is a Taiwanese stock, treat it as such. If US, treat as US).

      Perform a comprehensive analysis based on:
      1. Fundamentals (Earnings, P/E, Revenue Growth, Industry position)
      2. Technicals (Moving Averages, RSI, MACD, Volume, Patterns)
      3. Chips/Flow (Institutional buying/selling, Insider moves - simulate realistic data based on typical behavior for this stock type if real-time is unavailable)

      Predict the market direction, calculate a success probability, and determine precise buy/sell points.
      Current date is ${new Date().toLocaleDateString()}.

      Ensure the prices are in the correct currency for the stock (TWD for TW stocks, USD for US stocks).
    `;

    // Using gemini-3-pro-preview for deep reasoning capability
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        thinkingConfig: { thinkingBudget: 2048 } // Allow some thinking for math/logic
      }
    });

    if (!response.text) {
      throw new Error("No response from AI");
    }

    const data = JSON.parse(response.text) as AIAnalysisResult;
    // Add timestamp manually
    data.timestamp = new Date().toLocaleString();

    return data;
  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

