export const analyzeStock = async (query: string): Promise<AIAnalysisResult> => {
  try {
    const prompt = `
      Act as a professional financial analyst specializing in the Taiwan Stock Market (TWSE/TPEX).
      Target Stock: "${query}"

      STEPS:
      1. USE GOOGLE SEARCH to find the CURRENT REAL-TIME price, today's change, and latest news for this stock.
      2. Verify the latest institutional buying/selling (Foreign/Investment Trust) status via search.
      3. Analyze the technical indicators based on the latest close price found.

      CRITICAL:
      - The price and data MUST be from the search results. DO NOT rely on outdated internal knowledge.
      - Currency must be TWD.

      Generate a comprehensive analysis in JSON format:
      - Fundamentals: Revenue (MoM, YoY), EPS, PE Ratio, Dividend Yield.
      - Technicals: MA (5, 10, 20, 60), KD, RSI, MACD status.
      - Chips (籌碼面): Foreign Investment (外資), Investment Trust (投信), Main主力 status.
    `;

    // Using gemini-3-pro-preview with Google Search tool
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        tools: [{googleSearch: {}}],
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        thinkingConfig: { thinkingBudget: 1024 } // Reduced budget to balance latency with search
      }
    });

    if (!response.text) {
      throw new Error("No response from AI");
    }

    const data = JSON.parse(response.text) as AIAnalysisResult;
    data.timestamp = new Date().toLocaleString('zh-TW');

    // Extract citations/sources from grounding metadata
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
        data.sources = chunks
            .map((c: any) => c.web)
            .filter((w: any) => w !== undefined)
            .map((w: any) => ({ title: w.title || 'Source', uri: w.uri || '#' }));
    }

    return data;
  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

