                <div className="flex gap-2 mb-4 relative z-10">
                    <input 
                        type="text" 
                        value={localSearch}
                        onChange={(e) => setLocalSearch(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleLocalSearch()}
