            <div className="glass-panel rounded-2xl p-6 text-center relative overflow-hidden">
                <div className="absolute top-0 right-0 p-2 opacity-10">
                    <TrendingUp size={100} />
                </div>
                <h3 className="text-white font-bold mb-2">AI 台股診斷</h3>
