  return (
    <div className="min-h-screen bg-tech-dark text-slate-200 font-sans selection:bg-neon-blue selection:text-white">

      {/* Navbar */}
      <nav className="border-b border-slate-800 bg-slate-900/80 backdrop-blur-md sticky top-0 z-50">
