        }
    } catch (e) {}

    const listsPrompt = `Fetch standard market ranking lists for TWSE from Yahoo/CMoney. Traditional Chinese.`;
    const strategiesPrompt = `Identify 3 current hot market themes/concepts for TWSE. Traditional Chinese.`;

