import React, { useState } from 'react';
import { Search, BarChart3, Zap, BrainCircuit, LayoutGrid, Settings, Gem, ChevronLeft } from 'lucide-react';
import Dashboard from './components/Dashboard';
import StockDetail from './components/StockDetail';
import { analyzeStock } from './services/geminiService';
import { AIAnalysisResult, AnalysisStatus, StockPreview } from './types';

// Tab Definitions
type Tab = 'market' | 'strategies' | 'settings';

function App() {
  const [activeTab, setActiveTab] = useState<Tab>('market');
  const [searchQuery, setSearchQuery] = useState('');
  const [status, setStatus] = useState<AnalysisStatus>(AnalysisStatus.IDLE);
  const [analysisData, setAnalysisData] = useState<AIAnalysisResult | null>(null);
  const [errorMsg, setErrorMsg] = useState('');
  const [analysisMode, setAnalysisMode] = useState<'flash' | 'pro'>('flash');

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!searchQuery.trim()) return;
    performAnalysis(searchQuery);
  };

  const updateHistory = (data: AIAnalysisResult) => {
    try {
      const savedHistory = localStorage.getItem('search_history_v1');
      let history: StockPreview[] = savedHistory ? JSON.parse(savedHistory) : [];

      const newEntry: StockPreview = {
        symbol: data.symbol,
        name: data.name,
        price: data.currentPrice.toString(),
        changePercent: data.changePercent,
        reason: `最後查詢: ${new Date().toLocaleTimeString('zh-TW')}`
      };

      history = history.filter(item => item.symbol !== data.symbol);
      history.unshift(newEntry);
      history = history.slice(0, 10);

      localStorage.setItem('search_history_v1', JSON.stringify(history));
    } catch (e) {
      console.warn("Failed to update search history", e);
    }
  };

  const performAnalysis = async (query: string) => {
    setStatus(AnalysisStatus.LOADING);
    setAnalysisData(null);
    setErrorMsg('');
    const symbol = query.trim().toUpperCase();
    setSearchQuery(symbol);

    try {
      const data = await analyzeStock(symbol, analysisMode);
      setAnalysisData(data);
      updateHistory(data);
      setStatus(AnalysisStatus.SUCCESS);
    } catch (err) {
      setErrorMsg("AI 分析失敗，請稍後重試。");
      setStatus(AnalysisStatus.ERROR);
    }
  };

  const handleBack = () => {
    setStatus(AnalysisStatus.IDLE);
    setAnalysisData(null);
    setSearchQuery('');
  };

  // --- Components for Layout ---

  const Header = () => (
    <header className="fixed top-0 left-0 right-0 z-50 pt-safe bg-slate-900/80 backdrop-blur-xl border-b border-white/5 transition-all duration-300">
      <div className="h-14 px-4 flex items-center justify-between">
        {status !== AnalysisStatus.IDLE ? (
          // Detail View Header
          <div className="flex items-center w-full gap-3">
             <button onClick={handleBack} className="p-2 -ml-2 text-white active-scale">
                <ChevronLeft size={24} />
             </button>
             <span className="font-bold text-lg text-white truncate">
                {analysisData ? `${analysisData.symbol} ${analysisData.name}` : '分析中...'}
             </span>
          </div>
        ) : (
          // Main Tab Headers
          <>
             {activeTab === 'market' && (
                <div className="w-full flex items-center gap-3">
                  <div className="bg-neon-blue p-1.5 rounded-lg shrink-0">
                    <BarChart3 className="h-5 w-5 text-white" />
                  </div>
                  <form onSubmit={handleSearch} className="flex-1 relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-500" />
                    <input
                      type="text"
                      inputMode="text"
                      enterKeyHint="search"
                      className="w-full bg-slate-800/80 border border-slate-700 rounded-full py-2 pl-9 pr-4 text-sm text-white placeholder-gray-500 focus:outline-none focus:border-neon-blue focus:ring-1 focus:ring-neon-blue"
                      placeholder="輸入代號 (2330)..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                    />
                  </form>
                </div>
             )}
             {activeTab === 'strategies' && (
                <div className="flex items-center gap-2">
                   <Gem className="text-yellow-400" />
                   <h1 className="text-xl font-bold text-white">尋寶策略</h1>
                </div>
             )}
             {activeTab === 'settings' && (
                <div className="flex items-center gap-2">
                   <Settings className="text-gray-400" />
                   <h1 className="text-xl font-bold text-white">設定</h1>
                </div>
             )}
          </>
        )}
      </div>
    </header>
  );

  const BottomTabBar = () => {
    // If we are in detail view, we can either hide the tabbar or keep it.
    // Native apps often hide it for deep details. Let's hide it if analyzing.
    if (status !== AnalysisStatus.IDLE) return null;

    const tabs: { id: Tab; label: string; icon: React.ReactNode }[] = [
      { id: 'market', label: '市場', icon: <LayoutGrid size={24} /> },
      { id: 'strategies', label: '尋寶', icon: <Gem size={24} /> },
      { id: 'settings', label: '設定', icon: <Settings size={24} /> },
    ];

    return (
      <nav className="fixed bottom-0 left-0 right-0 z-50 bg-slate-900/90 backdrop-blur-2xl border-t border-white/5 pb-safe">
        <div className="flex items-center justify-around h-16">
          {tabs.map((tab) => {
            const isActive = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`flex flex-col items-center justify-center w-full h-full space-y-1 active-scale transition-colors ${
                  isActive ? 'text-neon-blue' : 'text-gray-500'
                }`}
              >
                {tab.icon}
                <span className="text-[10px] font-medium">{tab.label}</span>
              </button>
            );
          })}
        </div>
      </nav>
    );
  };

  const SettingsView = () => (
    <div className="p-4 space-y-6">
        <div className="glass-panel p-5 rounded-2xl">
            <h3 className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-4">分析模式 (Analysis Mode)</h3>
            <div className="flex bg-slate-800 p-1 rounded-xl border border-slate-700">
                <button 
                    onClick={() => setAnalysisMode('flash')}
                    className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-sm font-bold transition-all active-scale ${analysisMode === 'flash' ? 'bg-neon-blue text-white shadow-lg' : 'text-gray-400'}`}
                >
                    <Zap size={16} />
                    <span>快速 (Flash)</span>
                </button>
                <button 
                    onClick={() => setAnalysisMode('pro')}
                    className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-sm font-bold transition-all active-scale ${analysisMode === 'pro' ? 'bg-neon-purple text-white shadow-lg' : 'text-gray-400'}`}
                >
                    <BrainCircuit size={16} />
                    <span>深度 (Pro)</span>
                </button>
            </div>
            <p className="text-xs text-gray-500 mt-3 leading-relaxed">
                {analysisMode === 'pro' 
                    ? 'Pro 模式：模擬專家思維鏈 (CoT)，分析時間較長 (約 15s)，但精準度與籌碼解讀能力最高。' 
                    : 'Flash 模式：專注於速度，適合盤中即時查詢價格與基本趨勢。'}
            </p>
        </div>

        <div className="glass-panel p-5 rounded-2xl">
            <h3 className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-4">關於</h3>
            <div className="flex items-center gap-3 mb-4">
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-neon-blue to-neon-purple flex items-center justify-center">
                    <BarChart3 className="text-white" />
                </div>
                <div>
                    <h4 className="font-bold text-white">StockWinner AI</h4>
                    <p className="text-xs text-gray-400">v2.0.0 (Native PWA)</p>
                </div>
            </div>
            <p className="text-xs text-gray-500">
                本應用程式使用 Google Gemini 3 模型進行即時股票分析。請注意，AI 生成資訊可能包含誤差，投資請自行審慎評估。
            </p>
        </div>
    </div>
  );

  // --- Main Render ---

  return (
    <div className="flex flex-col h-full bg-tech-dark text-slate-200 font-sans">
      <Header />

      {/* Scrollable Content Area */}
      {/* pt-14 accounts for header, pb-20 accounts for tabbar (16 + safe area) */}
      <main className={`flex-1 native-scroll pt-14 ${status === AnalysisStatus.IDLE ? 'pb-24' : 'pb-safe'}`}>

        {status === AnalysisStatus.IDLE ? (
          // Tab Views
          <>
            {activeTab === 'market' && (
              <Dashboard onSelectStock={performAnalysis} initialTab="history" />
            )}

            {activeTab === 'strategies' && (
               <Dashboard onSelectStock={performAnalysis} initialTab="strategies" hideSearch />
            )}

            {activeTab === 'settings' && <SettingsView />}
          </>
        ) : (
          // Analysis / Loading Views
          <>
            {status === AnalysisStatus.LOADING && (
                <div className="flex flex-col items-center justify-center h-[70vh] px-6">
                    <div className="relative mb-8">
                        <div className={`w-20 h-20 border-4 border-t-transparent ${analysisMode === 'pro' ? 'border-neon-purple' : 'border-neon-blue'} rounded-full animate-spin`}></div>
                        <div className="absolute inset-0 flex items-center justify-center">
                            {analysisMode === 'pro' ? <BrainCircuit className="text-neon-purple animate-pulse" size={24} /> : <Zap className="text-neon-blue animate-pulse" size={24} />}
                        </div>
                    </div>
                    <h2 className="text-xl font-bold text-white mb-2 text-center">
                        {analysisMode === 'pro' ? '深度推演中...' : '掃描市場中...'}
                    </h2>
                    <p className="text-sm text-gray-400 text-center leading-relaxed">
                        {analysisMode === 'pro' 
                            ? 'AI 正在分析籌碼結構與技術型態' 
                            : '正在檢索即時報價'}
                    </p>
                </div>
            )}

            {status === AnalysisStatus.ERROR && (
                <div className="flex flex-col items-center justify-center h-[70vh] px-6 text-center">
                    <div className="bg-neon-red/10 p-4 rounded-full mb-4">
                        <Search className="w-8 h-8 text-neon-red" />
                    </div>
                    <h3 className="text-lg font-bold text-white mb-2">分析中斷</h3>
                    <p className="text-sm text-gray-400 mb-6">{errorMsg}</p>
                    <button 
                        onClick={handleBack}
                        className="w-full max-w-xs py-3 bg-slate-800 active:bg-slate-700 rounded-xl text-white font-bold transition-colors"
                    >
                        重試
                    </button>
                </div>
            )}

            {status === AnalysisStatus.SUCCESS && analysisData && (
                <StockDetail data={analysisData} onBack={handleBack} />
            )}
          </>
        )}
      </main>

      <BottomTabBar />
    </div>
  );
}

