import React, { useEffect, useState } from 'react';
import { getDashboardData } from '../services/geminiService';
import { DashboardData, StockPreview } from '../types';
import { 
  Flame, 
  DollarSign, 
  BarChart2, 
  Users,
  Percent,
  History,
  Info,
  ListFilter,
  ArrowRight,
  Globe,
  Sparkles
} from 'lucide-react';

interface DashboardProps {
  onSelectStock: (symbol: string) => void;
  initialTab?: string;
  hideSearch?: boolean;
}

// Combine standard tabs with string for dynamic strategy IDs
type TabType = 'trending' | 'fundamental' | 'technical' | 'chips' | 'dividend' | 'history' | 'strategies' | string;

const Dashboard: React.FC<DashboardProps> = ({ onSelectStock, initialTab = 'trending', hideSearch = false }) => {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<TabType>(initialTab);
  const [searchHistory, setSearchHistory] = useState<StockPreview[]>([]);

  useEffect(() => {
    // If we are strictly in "strategies" mode (from parent), prevent switching to other standard tabs via UI if needed, 
    // but here we just set the default.
    setActiveTab(initialTab);
  }, [initialTab]);

  useEffect(() => {
    const loadMarket = async () => {
        try {
            // Only fetch if we need fresh data, or if we haven't loaded yet
            if (!data) {
                const dashboardData = await getDashboardData();
                setData(dashboardData);
            }
        } catch(e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    const savedHistory = localStorage.getItem('search_history_v1');
    if (savedHistory) {
      setSearchHistory(JSON.parse(savedHistory));
    }

    loadMarket();
  }, []);

  const standardTabs: { id: TabType; label: string; icon: React.ReactElement; color: string }[] = [
    { id: 'history', label: '最近查詢', icon: <History className="w-4 h-4" />, color: 'text-neon-blue' },
    { id: 'trending', label: '熱門', icon: <Flame className="w-4 h-4" />, color: 'text-orange-500' },
    { id: 'fundamental', label: '績優', icon: <DollarSign className="w-4 h-4" />, color: 'text-emerald-500' },
    { id: 'technical', label: '強勢', icon: <BarChart2 className="w-4 h-4" />, color: 'text-blue-500' },
    { id: 'chips', label: '法人', icon: <Users className="w-4 h-4" />, color: 'text-purple-500' },
    { id: 'dividend', label: '殖利率', icon: <Percent className="w-4 h-4" />, color: 'text-yellow-500' },
  ];

  const getCurrentList = (): StockPreview[] => {
      if (activeTab === 'history') return searchHistory;
      if (activeTab === 'strategies') return []; // Handled separately
      if (!data) return [];

      if (activeTab === 'trending') return data.trending;
      if (activeTab === 'fundamental') return data.fundamental;
      if (activeTab === 'technical') return data.technical;
      if (activeTab === 'chips') return data.chips;
      if (activeTab === 'dividend') return data.dividend;

      const strategy = data.strategies.find(s => s.id === activeTab);
      return strategy ? strategy.stocks : [];
  };

  const currentList = getCurrentList();
  const isStrategyView = activeTab === 'strategies' || initialTab === 'strategies';

  return (
    <div className="animate-fade-in">

      {/* Horizontal Segmented Control (Sticky) */}
      {!isStrategyView && (
          <div className="sticky top-14 z-40 bg-tech-dark/95 backdrop-blur border-b border-white/5 pb-2 pt-2 -mt-2">
            <div className="flex overflow-x-auto scrollbar-hide px-4 gap-2 snap-x">
                {standardTabs.map(tab => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`snap-start shrink-0 px-4 py-2 rounded-full text-xs font-bold transition-all border ${
                            activeTab === tab.id 
                            ? 'bg-slate-700 text-white border-slate-600 shadow-sm' 
                            : 'bg-transparent text-gray-500 border-transparent active:bg-slate-800'
                        }`}
                    >
                        <div className="flex items-center gap-2">
                            {activeTab === tab.id && tab.icon}
                            {tab.label}
                        </div>
                    </button>
                ))}
            </div>
          </div>
      )}

      <div className="px-4 py-4">
        {loading && !data ? (
            <div className="flex flex-col items-center justify-center py-20">
                <div className="w-8 h-8 border-2 border-slate-600 border-t-neon-blue rounded-full animate-spin mb-4"></div>
                <p className="text-xs text-gray-500">更新數據中...</p>
            </div>
        ) : (
            <>
                {/* Mode: Strategy List */}
                {isStrategyView ? (
                    <div className="space-y-4">
                        {data && data.strategies.length > 0 ? (
                            data.strategies.map(strat => (
                                <div 
                                    key={strat.id}
                                    onClick={() => {
                                        // Normally this would navigate to a detailed list, 
                                        // for simplicity we can just expand it or treat it as a category.
                                        // But per spec, let's keep it simple.
                                    }}
                                    className="glass-panel p-5 rounded-2xl active-scale"
                                >
                                    <div className="flex justify-between items-start mb-2">
                                        <div className="flex items-center gap-2">
                                            <Sparkles size={16} className="text-yellow-400" />
                                            <h3 className="text-lg font-bold text-white">{strat.name}</h3>
                                        </div>
                                    </div>
                                    <p className="text-sm text-gray-400 mb-4 line-clamp-2">{strat.description}</p>

                                    {/* Mini Preview List */}
                                    <div className="space-y-2">
                                        {strat.stocks.slice(0, 3).map((stock, i) => (
                                            <div key={i} onClick={(e) => { e.stopPropagation(); onSelectStock(stock.symbol); }} className="flex justify-between items-center py-2 border-b border-white/5 last:border-0 active:bg-white/5 -mx-2 px-2 rounded">
                                                <div className="flex items-center gap-3">
                                                    <span className="font-bold text-white font-mono">{stock.symbol}</span>
                                                    <span className="text-sm text-gray-400 truncate w-24">{stock.name}</span>
                                                </div>
                                                <span className={`text-sm font-bold ${stock.changePercent >= 0 ? 'text-neon-red' : 'text-neon-green'}`}>
                                                    {stock.changePercent > 0 ? '+' : ''}{stock.changePercent}%
                                                </span>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="mt-3 text-xs text-gray-600 flex items-center gap-1">
                                        <Globe size={10} /> {strat.source}
                                    </div>
                                </div>
                            ))
                        ) : (
                           <div className="text-center py-10 text-gray-500 text-sm">暫無策略數據</div> 
                        )}
                    </div>
                ) : (
                    /* Mode: Standard List */
                    <div className="space-y-3">
                         {activeTab === 'history' && currentList.length === 0 && (
                            <div className="text-center py-20">
                                <History className="w-12 h-12 text-slate-700 mx-auto mb-3" />
                                <p className="text-gray-500 text-sm">尚無搜尋紀錄</p>
                            </div>
                         )}

                         {currentList.map((stock, idx) => (
                            <div 
                                key={`${stock.symbol}-${idx}`}
                                onClick={() => onSelectStock(stock.symbol)}
                                className="glass-panel p-4 rounded-xl flex items-center justify-between active-scale relative overflow-hidden"
                            >
                                <div className="flex items-center gap-4">
                                    <div className={`w-1 h-10 rounded-full ${stock.changePercent >= 0 ? 'bg-neon-red' : 'bg-neon-green'}`}></div>
                                    <div>
                                        <div className="flex items-baseline gap-2">
                                            <span className="text-lg font-black text-white tracking-tight">{stock.symbol}</span>
                                            <span className="text-sm text-gray-400">{stock.name}</span>
                                        </div>
                                        {stock.reason && activeTab !== 'history' && (
                                            <div className="text-[10px] text-gray-500 mt-1 flex items-center gap-1">
                                                <Info size={10} />
                                                <span className="truncate max-w-[150px]">{stock.reason}</span>
                                            </div>
                                        )}
                                        {activeTab === 'history' && (
                                            <div className="text-[10px] text-gray-600 mt-1">
                                                {stock.reason}
                                            </div>
                                        )}
                                    </div>
                                </div>
                                <div className="text-right">
                                    <div className="text-base font-bold text-white font-mono">{stock.price}</div>
                                    <div className={`text-xs font-bold px-1.5 py-0.5 rounded inline-block mt-1 ${stock.changePercent >= 0 ? 'bg-neon-red/10 text-neon-red' : 'bg-neon-green/10 text-neon-green'}`}>
                                        {stock.changePercent > 0 ? '+' : ''}{stock.changePercent}%
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

