const StrategyCard = ({ strategy, type }: { strategy: TimeframeStrategy, type: 'short' | 'medium' | 'long' }) => {
  if (!strategy) return null;

  const config = {
    short: { title: '短線 (1-3天)', icon: <Zap size={14} />, color: 'text-cyan-400', border: 'border-cyan-400/30' },
    medium: { title: '波段 (1-3週)', icon: <Calendar size={14} />, color: 'text-yellow-400', border: 'border-yellow-400/30' },
    long: { title: '長線 (1-3月)', icon: <Anchor size={14} />, color: 'text-purple-400', border: 'border-purple-400/30' },
  }[type];

  const actionColor = 
    strategy.action === 'BUY' ? 'bg-neon-red text-white' : 
    strategy.action === 'SELL' ? 'bg-neon-green text-white' : 
    strategy.action === 'OBSERVE' ? 'bg-gray-600 text-gray-200' :
    'bg-yellow-500 text-black'; // HOLD

  const actionText = 
    strategy.action === 'BUY' ? '偏多' : 
    strategy.action === 'SELL' ? '偏空' : 
    strategy.action === 'OBSERVE' ? '觀望' : '續抱';

  return (
    <div className={`bg-slate-900/40 p-3 rounded-xl border ${config.border} flex flex-col h-full active-scale`}>
       <div className={`flex items-center gap-2 mb-2 font-bold ${config.color} text-xs`}>
          {config.icon}
          {config.title}
       </div>
       <div className="flex justify-between items-center mb-2">
          <span className={`px-2 py-0.5 rounded text-[10px] font-bold ${actionColor}`}>
             {actionText}
          </span>
          <span className="text-white text-xs font-mono">{strategy.priceTarget}</span>
       </div>
       <p className="text-[10px] text-gray-400 leading-relaxed flex-1">
          {strategy.suggestion}
       </p>
    </div>
  );
};

