import React, { useState } from 'react';
import { Search, BarChart3, Zap, BrainCircuit, LayoutGrid } from 'lucide-react';
import Dashboard from './components/Dashboard';
import StockDetail from './components/StockDetail';
import { analyzeStock } from './services/geminiService';
import { AIAnalysisResult, AnalysisStatus, StockPreview } from './types';

function App() {
  const [searchQuery, setSearchQuery] = useState('');
  const [status, setStatus] = useState<AnalysisStatus>(AnalysisStatus.IDLE);
  const [analysisData, setAnalysisData] = useState<AIAnalysisResult | null>(null);
  const [errorMsg, setErrorMsg] = useState('');
  const [analysisMode, setAnalysisMode] = useState<'flash' | 'pro'>('flash');

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!searchQuery.trim()) return;
    performAnalysis(searchQuery);
  };

  const updateHistory = (data: AIAnalysisResult) => {
    try {
      const savedHistory = localStorage.getItem('search_history_v1');
      let history: StockPreview[] = savedHistory ? JSON.parse(savedHistory) : [];

      const newEntry: StockPreview = {
        symbol: data.symbol,
        name: data.name,
        price: data.currentPrice.toString(),
        changePercent: data.changePercent,
        reason: `最後查詢: ${new Date().toLocaleTimeString('zh-TW')}`
      };

      // Remove duplicate if exists, add to top
      history = history.filter(item => item.symbol !== data.symbol);
      history.unshift(newEntry);
      history = history.slice(0, 10); // Keep last 10

      localStorage.setItem('search_history_v1', JSON.stringify(history));
    } catch (e) {
      console.warn("Failed to update search history", e);
    }
  };

  const performAnalysis = async (query: string) => {
    setStatus(AnalysisStatus.LOADING);
    setAnalysisData(null);
    setErrorMsg('');
    const symbol = query.trim().toUpperCase();
    setSearchQuery(symbol);

    try {
      const data = await analyzeStock(symbol, analysisMode);
      setAnalysisData(data);
      updateHistory(data);
      setStatus(AnalysisStatus.SUCCESS);
    } catch (err) {
      console.error(err);
      setErrorMsg("AI 分析失敗，請確認代號正確或稍後重試。");
      setStatus(AnalysisStatus.ERROR);
    }
  };

  const handleBack = () => {
    setStatus(AnalysisStatus.IDLE);
    setAnalysisData(null);
    setSearchQuery('');
  };

  return (
    <div className="min-h-screen bg-tech-dark text-slate-200 font-sans p-4 md:p-8">
      <div className="max-w-5xl mx-auto">

        {/* Header Section */}
        <header className="flex flex-col md:flex-row items-center justify-between gap-6 mb-8">
          <div className="flex items-center gap-3 cursor-pointer" onClick={handleBack}>
            <div className="bg-gradient-to-br from-neon-blue to-neon-purple p-2.5 rounded-xl shadow-lg shadow-neon-blue/20">
              <BarChart3 className="text-white w-6 h-6" />
            </div>
            <div>
               <h1 className="text-2xl font-black text-white tracking-tight">StockWinner AI</h1>
               <p className="text-xs text-gray-400 font-medium tracking-wide">智能股票贏家</p>
            </div>
          </div>

          <div className="w-full md:w-auto flex flex-col md:flex-row gap-4 items-stretch">
            {/* Mode Toggle */}
            <div className="flex bg-slate-800/50 p-1 rounded-lg border border-slate-700/50">
                <button 
                    onClick={() => setAnalysisMode('flash')}
                    className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-bold transition-all ${analysisMode === 'flash' ? 'bg-neon-blue text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
                >
                    <Zap size={16} />
                    Flash
                </button>
                <button 
                    onClick={() => setAnalysisMode('pro')}
                    className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-bold transition-all ${analysisMode === 'pro' ? 'bg-neon-purple text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
                >
                    <BrainCircuit size={16} />
                    Pro
                </button>
            </div>

            {/* Search Bar */}
            <form onSubmit={handleSearch} className="relative w-full md:w-80 group">
              <input 
                type="text" 
                placeholder="輸入股票代號 (例: 2330)..."
                className="w-full bg-slate-800/50 border border-slate-700 text-white px-5 py-3 pl-11 rounded-xl focus:outline-none focus:ring-2 focus:ring-neon-blue/50 focus:border-neon-blue transition-all shadow-inner"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-neon-blue transition-colors" size={18} />
            </form>
          </div>
        </header>

        {/* Main Content Area */}
        <main className="transition-all duration-500 ease-in-out">
          {status === AnalysisStatus.IDLE && (
             <Dashboard onSelectStock={performAnalysis} />
          )}

          {status === AnalysisStatus.LOADING && (
             <div className="glass-panel rounded-3xl p-12 text-center animate-fade-in flex flex-col items-center justify-center min-h-[400px]">
                <div className="relative mb-8">
                    <div className={`w-24 h-24 border-4 border-t-transparent ${analysisMode === 'pro' ? 'border-neon-purple' : 'border-neon-blue'} rounded-full animate-spin`}></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                        {analysisMode === 'pro' ? <BrainCircuit className="text-neon-purple animate-pulse" size={32} /> : <Zap className="text-neon-blue animate-pulse" size={32} />}
                    </div>
                </div>
                <h2 className="text-2xl font-bold text-white mb-2">AI 正在深度分析中</h2>
                <p className="text-gray-400 animate-pulse">
                    {analysisMode === 'pro' ? '正在進行思維鏈推演、籌碼結構分析與策略制定...' : '正在檢索即時報價與市場數據...'}
                </p>
             </div>
          )}

          {status === AnalysisStatus.ERROR && (
             <div className="glass-panel rounded-3xl p-12 text-center animate-fade-in border-neon-red/30">
                <div className="bg-neon-red/10 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6">
                    <Search className="text-neon-red w-8 h-8" />
                </div>
                <h2 className="text-xl font-bold text-white mb-2">分析中斷</h2>
                <p className="text-gray-400 mb-6">{errorMsg}</p>
                <button onClick={handleBack} className="bg-slate-700 hover:bg-slate-600 text-white px-8 py-3 rounded-xl font-bold transition-colors">
                    返回首頁
                </button>
             </div>
          )}

          {status === AnalysisStatus.SUCCESS && analysisData && (
             <StockDetail data={analysisData} onBack={handleBack} />
          )}
        </main>

        <footer className="mt-12 text-center text-gray-600 text-xs pb-4">
            <p>&copy; 2024 StockWinner AI. Powered by Google Gemini 3.</p>
        </footer>
      </div>
    </div>
  );
}

