import React, { useEffect, useState } from 'react';
import { getDashboardData } from '../services/geminiService';
import { DashboardData, StockPreview } from '../types';
import { 
  Flame, 
  DollarSign, 
  BarChart2, 
  Users,
  Percent,
  History,
  Info,
  ExternalLink,
  ArrowRight,
  Globe,
  Sparkles
} from 'lucide-react';

interface DashboardProps {
  onSelectStock: (symbol: string) => void;
  initialTab?: string;
  hideSearch?: boolean; // Kept for interface compatibility but not used in standard view
}

type TabType = 'trending' | 'fundamental' | 'technical' | 'chips' | 'dividend' | 'history' | 'strategies' | string;

const Dashboard: React.FC<DashboardProps> = ({ onSelectStock }) => {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<TabType>('trending');
  const [searchHistory, setSearchHistory] = useState<StockPreview[]>([]);

  useEffect(() => {
    const loadMarket = async () => {
        try {
            if (!data) {
                const dashboardData = await getDashboardData();
                setData(dashboardData);
            }
        } catch(e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    const savedHistory = localStorage.getItem('search_history_v1');
    if (savedHistory) {
      setSearchHistory(JSON.parse(savedHistory));
    }

    loadMarket();
  }, []);

  const standardTabs: { id: TabType; label: string; icon: React.ReactElement; color: string }[] = [
    { id: 'trending', label: '熱門交易', icon: <Flame className="w-4 h-4" />, color: 'text-orange-500' },
    { id: 'fundamental', label: '績優股', icon: <DollarSign className="w-4 h-4" />, color: 'text-emerald-500' },
    { id: 'technical', label: '強勢股', icon: <BarChart2 className="w-4 h-4" />, color: 'text-blue-500' },
    { id: 'chips', label: '法人買超', icon: <Users className="w-4 h-4" />, color: 'text-purple-500' },
    { id: 'dividend', label: '高殖利率', icon: <Percent className="w-4 h-4" />, color: 'text-yellow-500' },
    { id: 'history', label: '最近查詢', icon: <History className="w-4 h-4" />, color: 'text-gray-400' },
  ];

  const getCurrentList = (): StockPreview[] => {
      if (activeTab === 'history') return searchHistory;
      if (!data) return [];

      if (activeTab === 'trending') return data.trending;
      if (activeTab === 'fundamental') return data.fundamental;
      if (activeTab === 'technical') return data.technical;
      if (activeTab === 'chips') return data.chips;
      if (activeTab === 'dividend') return data.dividend;

      const strategy = data.strategies.find(s => s.id === activeTab);
      return strategy ? strategy.stocks : [];
  };

  const currentList = getCurrentList();

  // Combine strategies into tabs if available
  const allTabs = [...standardTabs];
  if (data?.strategies) {
      data.strategies.forEach(s => {
          allTabs.push({ id: s.id, label: s.name, icon: <Sparkles className="w-4 h-4" />, color: 'text-yellow-400' });
      });
  }

  return (
    <div className="animate-fade-in space-y-6">

      {/* Tabs Container */}
      <div className="flex flex-wrap gap-2 pb-2 border-b border-gray-800">
        {allTabs.map(tab => (
            <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold transition-all border ${
                    activeTab === tab.id 
                    ? 'bg-slate-800 text-white border-slate-700 shadow-lg scale-105' 
                    : 'bg-transparent text-gray-500 border-transparent hover:bg-slate-800/50 hover:text-gray-300'
                }`}
            >
                <span className={activeTab === tab.id ? tab.color : ''}>{tab.icon}</span>
                {tab.label}
            </button>
        ))}
      </div>

      {/* Strategy Description Header */}
      {data?.strategies.find(s => s.id === activeTab) && (
          <div className="bg-gradient-to-r from-slate-800 to-slate-900 p-4 rounded-xl border border-slate-700 flex items-start gap-3">
              <Sparkles className="text-yellow-400 shrink-0 mt-1" size={20} />
              <div>
                  <h3 className="text-white font-bold mb-1">{data.strategies.find(s => s.id === activeTab)?.name}</h3>
                  <p className="text-gray-400 text-sm">{data.strategies.find(s => s.id === activeTab)?.description}</p>
                  <div className="mt-2 text-xs text-gray-500 flex items-center gap-1">
                      <Globe size={12} />
                      來源: {data.strategies.find(s => s.id === activeTab)?.source}
                  </div>
              </div>
          </div>
      )}

      {/* Grid Content */}
      <div className="min-h-[300px]">
        {loading && !data ? (
            <div className="flex flex-col items-center justify-center py-20">
                <div className="w-8 h-8 border-2 border-slate-600 border-t-neon-blue rounded-full animate-spin mb-4"></div>
                <p className="text-sm text-gray-500">正在分析市場數據...</p>
            </div>
        ) : (
            <>
                 {activeTab === 'history' && currentList.length === 0 && (
                    <div className="text-center py-20 bg-slate-800/30 rounded-2xl border border-dashed border-slate-700">
                        <History className="w-12 h-12 text-slate-700 mx-auto mb-3" />
                        <p className="text-gray-500">尚無搜尋紀錄</p>
                    </div>
                 )}

                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {currentList.map((stock, idx) => (
                        <div 
                            key={`${stock.symbol}-${idx}`}
                            onClick={() => onSelectStock(stock.symbol)}
                            className="glass-panel p-5 rounded-xl cursor-pointer hover:bg-slate-800/80 transition-all hover:scale-[1.02] hover:shadow-xl group relative overflow-hidden"
                        >
                            <div className="flex justify-between items-start mb-3">
                                <div>
                                    <div className="flex items-center gap-2">
                                        <span className="bg-slate-900 text-white px-2 py-1 rounded text-xs font-mono font-bold">{stock.symbol}</span>
                                        <h3 className="font-bold text-white text-lg group-hover:text-neon-blue transition-colors">{stock.name}</h3>
                                    </div>
                                    {stock.reason && activeTab !== 'history' && (
                                        <div className="flex items-center gap-1 text-xs text-gray-500 mt-2">
                                            <Info size={12} />
                                            <span className="truncate max-w-[200px]">{stock.reason}</span>
                                        </div>
                                    )}
                                    {activeTab === 'history' && (
                                        <div className="text-xs text-gray-600 mt-2">{stock.reason}</div>
                                    )}
                                </div>
                                <div className="text-right">
                                    <div className="text-xl font-bold text-white font-mono">{stock.price}</div>
                                    <div className={`text-sm font-bold flex items-center justify-end gap-1 ${stock.changePercent >= 0 ? 'text-neon-red' : 'text-neon-green'}`}>
                                        {stock.changePercent > 0 ? '+' : ''}{stock.changePercent}%
                                    </div>
                                </div>
                            </div>

                            <div className="absolute bottom-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity transform translate-x-2 group-hover:translate-x-0">
                                <div className="bg-neon-blue rounded-full p-1.5">
                                    <ArrowRight size={14} className="text-white" />
                                </div>
                            </div>
                        </div>
                    ))}
                 </div>
            </>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

