                        <item.icon size={18} style={{ color: item.color }} />
                     </div>
                     <h4 className="font-bold text-white">{item.title}</h4>
                     <div className="ml-auto font-mono text-xl font-bold" style={{ color: item.color }}>
                        {item.data?.score}
                     </div>
                 </div>
                 <p className="text-sm text-gray-300 leading-relaxed mb-4 min-h-[40px]">{item.data?.summary}</p>
                 <ul className="space-y-2">
                    {item.data?.details.map((d, idx) => (
                        <li key={idx} className="text-xs text-gray-500 flex items-start gap-2">
                            <span className="mt-1 w-1.5 h-1.5 rounded-full shrink-0" style={{ backgroundColor: item.color }}></span>
                            {d}
                        </li>
                    ))}
                 </ul>
             </div>
          ))}
      </div>

      {/* Sources Footer */}
      <div className="border-t border-gray-800 pt-6 mt-8">
         <h4 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-3">資料來源與參考</h4>
         <div className="flex flex-wrap gap-2">
             {data.sources && data.sources.length > 0 ? (
                 data.sources.map((s, i) => (
                     <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-xs text-neon-blue bg-neon-blue/10 px-3 py-1.5 rounded-full hover:bg-neon-blue/20 transition-colors">
                         <ExternalLink size={10} />
                         {s.title}
                     </a>
                 ))
             ) : (
                 <span className="text-xs text-gray-600">AI 綜合檢索分析 (Yahoo Finance, CMoney, TWSE)</span>
             )}
         </div>
      </div>
    </div>
  );
};

export default StockDetail;

import React, { useState } from 'react';
import { Search, BarChart3, Zap, BrainCircuit } from 'lucide-react';
import Dashboard from './components/Dashboard';
import StockDetail from './components/StockDetail';
import { analyzeStock } from './services/geminiService';
import { AIAnalysisResult, AnalysisStatus, StockPreview } from './types';

function App() {
  const [searchQuery, setSearchQuery] = useState('');
  const [status, setStatus] = useState<AnalysisStatus>(AnalysisStatus.IDLE);
  const [analysisData, setAnalysisData] = useState<AIAnalysisResult | null>(null);
  const [errorMsg, setErrorMsg] = useState('');
  const [analysisMode, setAnalysisMode] = useState<'flash' | 'pro'>('flash');

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!searchQuery.trim()) return;
    performAnalysis(searchQuery);
  };

  const updateHistory = (data: AIAnalysisResult) => {
    try {
      const savedHistory = localStorage.getItem('search_history_v1');
      let history: StockPreview[] = savedHistory ? JSON.parse(savedHistory) : [];

      const newEntry: StockPreview = {
        symbol: data.symbol,
        name: data.name,
        price: data.currentPrice.toString(),
        changePercent: data.changePercent,
        reason: `最後查詢: ${new Date().toLocaleTimeString('zh-TW')}`
      };

      history = history.filter(item => item.symbol !== data.symbol);
      history.unshift(newEntry);
      history = history.slice(0, 10); 

      localStorage.setItem('search_history_v1', JSON.stringify(history));
    } catch (e) {
      console.warn("Failed to update search history", e);
    }
  };

  const performAnalysis = async (query: string) => {
    setStatus(AnalysisStatus.LOADING);
    setAnalysisData(null);
    setErrorMsg('');
    const symbol = query.trim().toUpperCase();
    setSearchQuery(symbol);

    try {
      const data = await analyzeStock(symbol, analysisMode);
      setAnalysisData(data);
      updateHistory(data);
      setStatus(AnalysisStatus.SUCCESS);
    } catch (err) {
      console.error(err);
      setErrorMsg("AI 分析失敗，請確認代號正確或稍後重試。");
      setStatus(AnalysisStatus.ERROR);
    }
  };

  const handleBack = () => {
    setStatus(AnalysisStatus.IDLE);
    setAnalysisData(null);
    setSearchQuery('');
  };

  return (
    <div className="min-h-screen bg-tech-dark text-slate-200 font-sans">
      {/* Navbar / Header */}
      <nav className="sticky top-0 z-50 bg-slate-900/80 backdrop-blur-md border-b border-slate-700/50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">

            {/* Logo */}
            <div className="flex items-center gap-3 cursor-pointer" onClick={handleBack}>
               <div className="bg-gradient-to-br from-neon-blue to-neon-purple p-2 rounded-lg shadow-lg shadow-neon-blue/20">
                 <BarChart3 className="text-white w-5 h-5" />
               </div>
               <span className="text-xl font-bold text-white tracking-tight">StockWinner AI</span>
            </div>

            {/* Desktop Search & Controls */}
            <div className="flex items-center gap-4">
               {/* Mode Switcher */}
               <div className="hidden md:flex bg-slate-800 p-1 rounded-lg border border-slate-700">
                  <button 
                      onClick={() => setAnalysisMode('flash')}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${analysisMode === 'flash' ? 'bg-neon-blue text-white shadow' : 'text-gray-400 hover:text-white'}`}
                  >
                      <Zap size={14} />
                      Flash
                  </button>
                  <button 
                      onClick={() => setAnalysisMode('pro')}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${analysisMode === 'pro' ? 'bg-neon-purple text-white shadow' : 'text-gray-400 hover:text-white'}`}
                  >
                      <BrainCircuit size={14} />
                      Pro
                  </button>
               </div>

               {/* Search Bar */}
               <form onSubmit={handleSearch} className="relative group">
                 <input 
                   type="text" 
                   placeholder="輸入代號 (2330)..."
                   className="w-40 md:w-64 bg-slate-800 border border-slate-700 text-white text-sm px-4 py-2 pl-9 rounded-full focus:outline-none focus:ring-2 focus:ring-neon-blue/50 focus:border-neon-blue transition-all"
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                 />
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 w-4 h-4 group-focus-within:text-neon-blue transition-colors" />
               </form>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 transition-all">
          {status === AnalysisStatus.IDLE && (
             <Dashboard onSelectStock={performAnalysis} />
          )}

          {status === AnalysisStatus.LOADING && (
             <div className="flex flex-col items-center justify-center min-h-[60vh] animate-fade-in">
                <div className="relative mb-8">
                    <div className={`w-20 h-20 border-4 border-t-transparent ${analysisMode === 'pro' ? 'border-neon-purple' : 'border-neon-blue'} rounded-full animate-spin`}></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                        {analysisMode === 'pro' ? <BrainCircuit className="text-neon-purple animate-pulse" size={28} /> : <Zap className="text-neon-blue animate-pulse" size={28} />}
                    </div>
                </div>
                <h2 className="text-2xl font-bold text-white mb-2">
                    {analysisMode === 'pro' ? '正在進行深度推演...' : '正在掃描市場數據...'}
                </h2>
                <p className="text-gray-400">
                    {analysisMode === 'pro' ? 'AI 正在分析籌碼結構與技術型態' : '正在檢索即時報價與基本面資料'}
                </p>
             </div>
          )}

          {status === AnalysisStatus.ERROR && (
             <div className="flex flex-col items-center justify-center min-h-[50vh] animate-fade-in text-center">
                <div className="bg-neon-red/10 p-4 rounded-full mb-6">
                    <Search className="text-neon-red w-8 h-8" />
                </div>
                <h2 className="text-xl font-bold text-white mb-2">分析中斷</h2>
                <p className="text-gray-400 mb-6 max-w-md">{errorMsg}</p>
                <button onClick={handleBack} className="bg-slate-700 hover:bg-slate-600 text-white px-6 py-2 rounded-lg font-bold transition-colors">
                    重新搜尋
                </button>
             </div>
          )}

          {status === AnalysisStatus.SUCCESS && analysisData && (
             <StockDetail data={analysisData} onBack={handleBack} />
          )}
      </main>
    </div>
  );
}

export default App;

import React, { useEffect, useState } from 'react';
import { getDashboardData } from '../services/geminiService';
import { DashboardData, StockPreview } from '../types';
import { 
  Flame, 
  DollarSign, 
  BarChart2, 
  Users,
  Percent,
  History,
  Info,
  ArrowRight,
  Globe,
  Sparkles,
  Layers
} from 'lucide-react';

interface DashboardProps {
  onSelectStock: (symbol: string) => void;
  initialTab?: string;
  hideSearch?: boolean; 
}

type TabType = 'trending' | 'fundamental' | 'technical' | 'chips' | 'dividend' | 'history' | 'strategies' | string;

const Dashboard: React.FC<DashboardProps> = ({ onSelectStock }) => {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<TabType>('trending');
  const [searchHistory, setSearchHistory] = useState<StockPreview[]>([]);

  useEffect(() => {
    const loadMarket = async () => {
        try {
            if (!data) {
                const dashboardData = await getDashboardData();
                setData(dashboardData);
            }
        } catch(e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    const savedHistory = localStorage.getItem('search_history_v1');
    if (savedHistory) {
      setSearchHistory(JSON.parse(savedHistory));
    }

    loadMarket();
  }, []);

  const standardTabs: { id: TabType; label: string; icon: React.ReactElement; color: string }[] = [
    { id: 'trending', label: '熱門交易', icon: <Flame className="w-4 h-4" />, color: 'text-orange-500' },
    { id: 'fundamental', label: '績優排行', icon: <DollarSign className="w-4 h-4" />, color: 'text-emerald-500' },
    { id: 'technical', label: '強勢型態', icon: <BarChart2 className="w-4 h-4" />, color: 'text-blue-500' },
    { id: 'chips', label: '法人買超', icon: <Users className="w-4 h-4" />, color: 'text-purple-500' },
    { id: 'dividend', label: '高殖利率', icon: <Percent className="w-4 h-4" />, color: 'text-yellow-500' },
    { id: 'history', label: '最近查詢', icon: <History className="w-4 h-4" />, color: 'text-gray-400' },
  ];

  const getCurrentList = (): StockPreview[] => {
      if (activeTab === 'history') return searchHistory;
      if (!data) return [];

      if (activeTab === 'trending') return data.trending;
      if (activeTab === 'fundamental') return data.fundamental;
      if (activeTab === 'technical') return data.technical;
      if (activeTab === 'chips') return data.chips;
      if (activeTab === 'dividend') return data.dividend;

      const strategy = data.strategies.find(s => s.id === activeTab);
      return strategy ? strategy.stocks : [];
  };

  const currentList = getCurrentList();

  // Combine strategies into tabs if available
  const allTabs = [...standardTabs];
  if (data?.strategies) {
      data.strategies.forEach(s => {
          allTabs.push({ id: s.id, label: s.name, icon: <Sparkles className="w-4 h-4" />, color: 'text-yellow-400' });
      });
  }

  return (
    <div className="flex flex-col md:flex-row gap-8 animate-fade-in">

      {/* Sidebar Navigation */}
      <aside className="w-full md:w-64 shrink-0 space-y-6">
        <div>
            <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-3 px-2">市場掃描</h3>
            <div className="space-y-1">
                {allTabs.filter(t => !data?.strategies.some(s => s.id === t.id)).map(tab => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all ${
                            activeTab === tab.id 
                            ? 'bg-slate-800 text-white shadow-lg border border-slate-700' 
                            : 'text-gray-400 hover:bg-slate-800/50 hover:text-white'
                        }`}
                    >
                        <span className={activeTab === tab.id ? tab.color : 'text-slate-500'}>{tab.icon}</span>
                        {tab.label}
                    </button>
                ))}
            </div>
        </div>

        {data?.strategies && data.strategies.length > 0 && (
            <div>
                <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-3 px-2">AI 發現題材</h3>
                <div className="space-y-1">
                    {data.strategies.map(strat => (
                        <button
                            key={strat.id}
                            onClick={() => setActiveTab(strat.id)}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all ${
                                activeTab === strat.id 
                                ? 'bg-slate-800 text-white shadow-lg border border-slate-700' 
                                : 'text-gray-400 hover:bg-slate-800/50 hover:text-white'
                            }`}
                        >
                            <Sparkles className={`w-4 h-4 ${activeTab === strat.id ? 'text-yellow-400' : 'text-slate-500'}`} />
                            {strat.name}
                        </button>
                    ))}
                </div>
            </div>
        )}
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 min-h-[500px]">
        {loading && !data ? (
            <div className="flex flex-col items-center justify-center h-full py-20">
                <div className="w-10 h-10 border-4 border-slate-700 border-t-neon-blue rounded-full animate-spin mb-4"></div>
                <p className="text-gray-500 font-medium">AI 正在分析全市場數據...</p>
            </div>
        ) : (
            <>
                 {/* Header for current section */}
                 <div className="flex items-center justify-between mb-6">
                    <div>
                        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                            {allTabs.find(t => t.id === activeTab)?.icon}
                            {allTabs.find(t => t.id === activeTab)?.label}
                        </h2>
                        {data?.strategies.find(s => s.id === activeTab) && (
                            <div className="flex items-center gap-2 mt-2 text-sm text-gray-400">
                                <Globe size={14} />
                                <span>來源: {data.strategies.find(s => s.id === activeTab)?.source}</span>
                            </div>
                        )}
                    </div>
                    {data?.strategies.find(s => s.id === activeTab) && (
                         <div className="bg-slate-800/50 px-4 py-2 rounded-lg border border-slate-700 max-w-md text-right hidden lg:block">
                            <p className="text-xs text-gray-300 italic">"{data.strategies.find(s => s.id === activeTab)?.description}"</p>
                         </div>
                    )}
                 </div>

                 {/* Empty State */}
                 {activeTab === 'history' && currentList.length === 0 && (
                    <div className="text-center py-20 bg-slate-800/30 rounded-2xl border border-dashed border-slate-700">
                        <History className="w-16 h-16 text-slate-700 mx-auto mb-4" />
                        <h3 className="text-lg font-bold text-white mb-2">尚無搜尋紀錄</h3>
                        <p className="text-gray-500">試著在上方搜尋欄輸入股票代號</p>
                    </div>
                 )}

                 {/* Grid */}
                 <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-5">
                    {currentList.map((stock, idx) => (
                        <div 
                            key={`${stock.symbol}-${idx}`}
                            onClick={() => onSelectStock(stock.symbol)}
                            className="glass-panel p-5 rounded-xl cursor-pointer hover:bg-slate-800 transition-all hover:-translate-y-1 hover:shadow-xl group relative overflow-hidden border border-slate-700/50 hover:border-neon-blue/50"
                        >
                            <div className="flex justify-between items-start mb-4">
                                <div>
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="bg-slate-900 text-white px-2 py-1 rounded text-sm font-mono font-bold tracking-wider">{stock.symbol}</span>
                                        {stock.changePercent > 3 && (
                                            <span className="bg-neon-red/10 text-neon-red text-[10px] px-1.5 py-0.5 rounded font-bold">強勢</span>
                                        )}
                                    </div>
                                    <h3 className="font-bold text-white text-lg group-hover:text-neon-blue transition-colors">{stock.name}</h3>
                                </div>
                                <div className="text-right">
                                    <div className="text-xl font-bold text-white font-mono tracking-tight">{stock.price}</div>
                                    <div className={`text-sm font-bold flex items-center justify-end gap-1 ${stock.changePercent >= 0 ? 'text-neon-red' : 'text-neon-green'}`}>
                                        {stock.changePercent > 0 ? '+' : ''}{stock.changePercent}%
                                    </div>
                                </div>
                            </div>

                            <div className="pt-3 border-t border-slate-700/50">
                                <div className="flex items-start gap-2">
                                    <Info className="w-4 h-4 text-gray-500 mt-0.5 shrink-0" />
                                    <p className="text-xs text-gray-400 leading-relaxed line-clamp-2">{stock.reason}</p>
                                </div>
                            </div>
                        </div>
                    ))}
                 </div>
            </>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
